script.text:

function active$VoucherFilter$(f) {f.add_onResponseComplete(on$Filter$ResponseComplete);}
function close$VoucherFilter$(f) {try {f.remove_onResponseComplete(on$Filter$ResponseComplete);} catch (ex) {}}
function on$Filter$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      var g = f.grid, k = [];      
      if (f.getItemValue('ma_dvcs')) Array.add(k, {Name: "dbo.ff_InList(ma_dvcs,'" + f.getItemValue('ma_dvcs') + "')", Opr: '=', Value: 1, Type: 'String', Ignore: false});
      g.set_externalKey(k);
      break;
    default:
      break;
  }
}
